func newOrdersPlanCmd(flags *rootFlags) *cobra.Command {
	// PATCH: Hand-written cart planning command composed around local order
	// reuse and the /m/api/orders tax/token validation endpoint.
	var reuseLast bool
	var restaurant string
	var itemsSpec string
	var tipSpec string
	var maxBudget float64
	var pickupAt string
	var confirmOverBudget bool

	cmd := &cobra.Command{
		Use:   "plan",
		Short: "Build and validate an order cart before checkout",
		Example: `  ordertogo-pp-cli orders plan --reuse-last --restaurant mixsushibarlin --max 30 --json
  ordertogo-pp-cli orders plan --restaurant mixsushibarlin --items 101x2,202x1 --tip 18% --max 40`,
		Annotations: map[string]string{"mcp:read-only": "true", "pp:typed-exit-codes": "0,3,4,5"},
		RunE: func(cmd *cobra.Command, args []string) error {
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return configErr(err)
			}
			if restaurant == "" {
				restaurant = cfg.DefaultRestaurant
			}
			if maxBudget == 0 {
				maxBudget = cfg.DefaultMax
			}

			if verifyMode() && flags.dryRun {
				fixture := activeCart{
					Restaurant: restaurant,
					Items:      []store.OrderItem{{ItemID: "fixture-1", Name: "Fixture item", Quantity: 2, Price: 8.99}},
					Totals:     orderTotals{Subtotal: 17.98, Tax: 1.85, Tip: 0.90, Total: 20.73},
					Budget:     map[string]any{"max": maxBudget, "status": "under"},
					Token:      "verify-plan-token",
					PickupAt:   pickupAt,
				}
				return printJSONFiltered(cmd.OutOrStdout(), fixture, flags)
			}

			items, restID, err := planItems(cmd, reuseLast, restaurant, itemsSpec)
			if err != nil {
				return err
			}
			if len(items) == 0 {
				return usageErr(fmt.Errorf("provide --items or --reuse-last"))
			}

			subtotal := subtotalForItems(items)
			body := map[string]any{"restid": restID, "items": items}
			c, err := flags.newClient()
			if err != nil {
				return err
			}
			data, _, err := c.Post("/m/api/orders", body)
			if err != nil {
				return classifyAPIError(err, flags)
			}
			token, tax := parsePlanValidation(data)
			tip, err := parseTip(tipSpec, subtotal, cfg)
			if err != nil {
				return usageErr(err)
			}
			totals := orderTotals{Subtotal: subtotal, Tax: tax, Tip: tip, Total: roundMoney(subtotal + tax + tip)}
			budgetStatus := "under"
			if maxBudget > 0 && totals.Total > maxBudget {
				budgetStatus = "over"
				if !confirmOverBudget {
					return budgetError(flags, "planned total exceeds --max", maxBudget, totals.Total)
				}
			}
			cart := activeCart{
				Restaurant:     restaurant,
				RestID:         restID,
				Items:          items,
				Totals:         totals,
				Budget:         map[string]any{"max": maxBudget, "status": budgetStatus},
				Token:          token,
				PickupAt:       pickupAt,
				CreatedAt:      time.Now(),
				ValidationBody: body,
			}
			if err := saveActiveCart(cart); err != nil {
				return configErr(fmt.Errorf("saving active cart: %w", err))
			}
			return printJSONFiltered(cmd.OutOrStdout(), cart, flags)
		},
	}
	cmd.Flags().BoolVar(&reuseLast, "reuse-last", false, "Load the last local order at this restaurant and copy its items")
	cmd.Flags().StringVar(&restaurant, "restaurant", "", "Restaurant slug")
	cmd.Flags().StringVar(&itemsSpec, "items", "", "Cart items as id1xN,id2xN")
	cmd.Flags().StringVar(&tipSpec, "tip", "auto", "Tip as auto, pct%, or dollars")
	cmd.Flags().Float64Var(&maxBudget, "max", 0, "Maximum allowed total in dollars")
	cmd.Flags().StringVar(&pickupAt, "pickup-at", "", "Requested pickup time")
	cmd.Flags().BoolVar(&confirmOverBudget, "confirm-over-budget", false, "Allow totals over --max")
	return cmd
}

func planItems(cmd *cobra.Command, reuseLast bool, restaurant, itemsSpec string) ([]store.OrderItem, string, error) {
	if reuseLast {
		db, err := store.OpenWithContext(cmd.Context(), defaultDBPath("ordertogo-pp-cli"))
		if err != nil {
			return nil, "", fmt.Errorf("opening local database: %w", err)
		}
		defer db.Close()
		order, err := db.LastOrder(restaurant)
		if err != nil {
			return nil, "", err
		}
		if order == nil {
			return nil, "", notFoundErr(fmt.Errorf("no last order found for %s", restaurant))
		}
		if restaurant == "" {
			restaurant = order.RestaurantSlug
		}
		return order.Items, order.RestID, nil
	}
	items, err := parseItemsSpec(itemsSpec)
	return items, restaurant, err
}

func parsePlanValidation(data json.RawMessage) (string, float64) {
	var obj map[string]any
	if json.Unmarshal(data, &obj) != nil {
		return "", 0
	}
	token := ""
	for _, key := range []string{"token", "orderToken", "order_token"} {
		if v, ok := obj[key]; ok {
			token = fmt.Sprintf("%v", v)
			break
		}
	}
	tax := 0.0
	for _, key := range []string{"tax", "salestax", "sales_tax"} {
		if v, ok := obj[key]; ok {
			switch n := v.(type) {
			case float64:
				tax = n
			case string:
				fmt.Sscanf(n, "%f", &tax)
			}
			break
		}
	}
	return token, roundMoney(tax)
}
